# @cctt_verify {"v":2,"sym":"sympy.matrices.expressions.tests.test_matadd.test_doit_args","kind":"function","src_hash":"cb478e06d09481d1","in":{"base":"Any"},"out":{"base":"Any","pred":"MatAdd(A, MatPow(B, 2)).doit() == A + B ** 2 and MatAdd(A, MatMul(A, B)).doit() == A + A * B"},"spec":{"lhs":"test_doit_args()","rhs":"test_doit_args produces the expected output","over":{"base":"Any"},"name":"test_doit_args_correct"},"guarantee":"test_doit_args produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.expressions.tests.test_matadd.test_doit_args_correct","statement":"Path(test_doit_args(x), test_doit_args produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"942e8164f3182313"}
def test_doit_args():
    A = ImmutableMatrix([[1, 2], [3, 4]])
    B = ImmutableMatrix([[2, 3], [4, 5]])
    assert MatAdd(A, MatPow(B, 2)).doit() == A + B**2
    assert MatAdd(A, MatMul(A, B)).doit() == A + A*B
    assert (MatAdd(A, X, MatMul(A, B), Y, MatAdd(2*A, B)).doit() ==
    add(A, X, MatMul(A, B), Y, add(2*A, B)).doit() ==
    MatAdd(3*A + A*B + B, X, Y))


